<?php namespace Blue\Controllers; use Blue\Core\Database; use Blue\Core\View; use Blue\Services\Audit;
class AuthController { public function login(){ if(!empty($_SESSION['user'])) redirect('/dashboard'); View::render('auth/login',['title'=>'Login']); } public function authenticate(){ $u=Database::one('SELECT * FROM users WHERE email=? AND status="active"',[$_POST['email']??'']); if($u && password_verify($_POST['password']??'', $u['password_hash'])){ $_SESSION['user']=['id'=>$u['id'],'name'=>$u['name'],'email'=>$u['email']]; Audit::log('login','user',$u['id']); redirect('/dashboard'); } flash('danger','Invalid login or inactive account.'); redirect('/login'); } public function logout(){ Audit::log('logout'); session_destroy(); redirect('/login'); } }
